import{_ as s,o as i,c as e,ae as t}from"./chunks/framework.D7zHIyZF.js";const u=JSON.parse('{"title":"Install / Build","description":"","frontmatter":{"title":"Install / Build"},"headers":[],"relativePath":"install.md","filePath":"install.md"}'),n={name:"install.md"};function l(o,a,d,h,r,p){return i(),e("div",null,[...a[0]||(a[0]=[t(`<h1 id="install-build" tabindex="-1">Install / Build <a class="header-anchor" href="#install-build" aria-label="Permalink to &quot;Install / Build&quot;">​</a></h1><p>jai is Linux-only and runs on kernel version 6.13 or later.</p><h2 id="package-install" tabindex="-1">Package install <a class="header-anchor" href="#package-install" aria-label="Permalink to &quot;Package install&quot;">​</a></h2><h3 id="arch-linux" tabindex="-1">Arch linux <a class="header-anchor" href="#arch-linux" aria-label="Permalink to &quot;Arch linux&quot;">​</a></h3><p>jai is available as an AUR package for arch linux. If you use an AUR helper such as <code>yay</code>, you should be able to install it directly:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">yay</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -S</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> jai</span></span></code></pre></div><p>Otherwise, you can install it manually as follows:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -L</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://aur.archlinux.org/cgit/aur.git/snapshot/jai.tar.gz</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> tar</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> xzf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> -</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> jai</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">makepkg</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -i</span></span></code></pre></div><h2 id="build-install-from-source" tabindex="-1">Build/install from source <a class="header-anchor" href="#build-install-from-source" aria-label="Permalink to &quot;Build/install from source&quot;">​</a></h2><h3 id="dependencies" tabindex="-1">Dependencies <a class="header-anchor" href="#dependencies" aria-label="Permalink to &quot;Dependencies&quot;">​</a></h3><p>jai requires:</p><ul><li>A C++23 compiler (verified on GCC 15 and Clang 22)</li><li><code>libmount</code> (from util-linux or libmount-dev)</li><li><code>libacl</code> (from acl or libacl1-dev)</li><li><code>pkg-config</code></li></ul><p>If you are building from git instead of a release, you also need:</p><ul><li>Standard autotools (<code>autoconf</code>, <code>automake</code>) for the build system</li><li><code>pandoc</code> to format the man page</li></ul><p>Most modern linux systems with a development environment installed should satisfy all of the above dependencies except <code>pandoc</code>, which is slightly less standard but still widely available.</p><h3 id="build" tabindex="-1">Build <a class="header-anchor" href="#build" aria-label="Permalink to &quot;Build&quot;">​</a></h3><p>You can install jai from a stable release (recommended), or from git.</p><p>jai requires a dedicated untrusted user for strict sandboxes, called <code>jai</code> by default. The jai user <em>must</em> be different from <code>nobody</code> (which is the &quot;overflow&quot; user in id-mapped mounts), and the account name will be embedded into the jai binary. If your system already has a user named <code>jai</code>, then jai will pick the name <code>_jai</code>. You can override this choice in the instructions below by changing the <code>./configure</code> to specify an alternate name, for instance <code>unprivileged</code>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>./configure --with-untrusted-user=unprivileged</span></span></code></pre></div><h4 id="building-a-release" tabindex="-1">Building a release <a class="header-anchor" href="#building-a-release" aria-label="Permalink to &quot;Building a release&quot;">​</a></h4><p>Download the <a href="https://github.com/stanford-scs/jai/releases/latest" target="_blank" rel="noreferrer">latest release</a> from github. Make sure to download the file called <code>jai-</code><em>version</em><code>.tar.gz</code>. (The assets labeled &quot;Source code&quot; are generated by github from the git tag; they are missing some generated files like the man page and configure script and so require additional tooling to build.)</p><p>Unpack, configure, and build the release as follows:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">tar</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> xzf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> jai-x.y.tar.gz</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> jai-x.y</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./configure</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">make</span></span></code></pre></div><h4 id="building-from-git" tabindex="-1">Building from git <a class="header-anchor" href="#building-from-git" aria-label="Permalink to &quot;Building from git&quot;">​</a></h4><p>To build the latest version from git, run the following commands:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clone</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/stanford-scs/jai.git</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> jai</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./autogen.sh</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./configure</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">make</span></span></code></pre></div><h3 id="installation" tabindex="-1">Installation <a class="header-anchor" href="#installation" aria-label="Permalink to &quot;Installation&quot;">​</a></h3><p>Run the following two commands to install jai and create the unprivileged <code>jai</code> user (if it does not already exist on your system):</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> make</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> systemd-sysusers</span></span></code></pre></div><p><a href="https://www.freedesktop.org/software/systemd/man/latest/sysusers.d.html" target="_blank" rel="noreferrer">systemd-sysusers</a> creates the unprivileged <code>jai</code> user account, but will only find the configuration file if you installed with a prefix of <code>/usr/local</code> (the default) or <code>/usr</code>. If you install jai elsewhere, you need to supply the <code>jai.conf</code> file as a command-line argument. For example, in the build directory:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> systemd-sysusers</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./jai.conf</span></span></code></pre></div><p>You can also just create an account named <code>jai</code>, but note that jai is very picky about the account. In the password file, the Gecos field must be exactly <code>JAI sandbox untrusted user</code> and the home directory must be <code>/</code>. Otherwise, jai is paranoid that you might have a real user named <code>jai</code> on your system. Here is a command to create the user manually:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">useradd</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -rMU</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -s</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /usr/bin/nologin</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -d</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -c</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;JAI sandbox untrusted user&#39;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> jai</span></span></code></pre></div><p>Note that jai must run as root (it uses <code>unshare</code> and various privileged file system and mount-related syscalls), so it gets installed setuid root. If you do not want to install it setuid root, you can install it manually and run it with sudo.</p><h2 id="first-run-setup" tabindex="-1">First-run setup <a class="header-anchor" href="#first-run-setup" aria-label="Permalink to &quot;First-run setup&quot;">​</a></h2><p>After installing, run:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">jai</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --init</span></span></code></pre></div><p>This creates default configuration files in <code>$HOME/.jai/</code>, including the <code>.defaults</code> file that ships sensible blacklists for sensitive dotfiles and environment variables.</p><h2 id="alternate-configuration-file-locations" tabindex="-1">Alternate configuration file locations <a class="header-anchor" href="#alternate-configuration-file-locations" aria-label="Permalink to &quot;Alternate configuration file locations&quot;">​</a></h2><p>If your home directory is on NFS, you may want to relocate jai&#39;s configuration and storage:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> JAI_CONFIG_DIR</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">/local/disk/.jai</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">jai</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --init</span></span></code></pre></div><p>This puts all configuration files, private home directories, and overlay storage on a local filesystem where extended attributes and overlayfs work correctly.</p><p>If you wish to keep configuration files in your home directory but move storage to local disk, then instead of setting <code>JAI_CONFIG_DIR</code> you can put a line <code>storage /local/disk/jai-storage</code> in <code>$HOME/.jai/.defaults</code> to move just the private home directory storage to local disk.</p>`,43)])])}const k=s(n,[["render",l]]);export{u as __pageData,k as default};
